#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char s[101];
    while(T--){
        scanf("%s",s);
        int len=strlen(s);
        printf("%c\n",s[len-1]);
    }
    return 0;
}

